select template_id, template_name, template_version, owner_type, owner_id,
       audit_status, status, effective_time, create_time, update_time
from jst_enroll_form_template

    del_flag = '0'

        and template_name like concat('%', #{query.templateName}, '%')


        and owner_type = #{query.ownerType}


        and owner_id = #{query.ownerId}


        and audit_status = #{query.auditStatus}


        and status = #{query.status}


order by update_time desc, template_id desc

