update jst_enroll_form_template
set audit_status = #{targetAuditStatus},
    effective_time = #{effectiveTime},
    update_by = #{updateBy},
    update_time = #{updateTime}
where template_id = #{templateId}
  and audit_status = #{expectedAuditStatus}
